#!/usr/bin/env python
# Convert robot-logo.png: thicker strokes, less padding, change color to #00c0b5
import sys; from PIL import Image, ImageOps; img = Image.open('/Users/rat/git/Robocorp-Recorder/robotframework-recorder-assets/robot-logo.png').convert('RGBA'); bbox = img.getbbox(); img_cropped = img.crop(bbox) if bbox else img; img_padded = ImageOps.expand(img_cropped, border=8, fill=(0,0,0,0)); pixels = img_padded.load(); pixels_list = [(x, y, (0, 192, 181, pixels[x,y][3]) if pixels[x,y][3] > 0 else (0,0,0,0)) for x in range(img_padded.width) for y in range(img_padded.height)]; [pixels.__setitem__((x,y), c) for x, y, c in pixels_list]; img_padded.save('/Users/rat/git/Robocorp-Recorder/robotframework-recorder-assets/robot-logo.png'); print("✅ Logo converted: color changed to #00c0b5, padding reduced")
